INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2176410','Брами вже замкнули','Музика: Генрик Варс Слова: Емануель Шлехтер. Виконує: Віктор Морозов','uk','ukraine_before_1917',NULL,NULL,'http://www.mo-productions.com/',NULL,'Брами вже замкнули
лілю-лілю-лі
квітки сплят і пташки сплят
і пси сплят і коти
оченятка стỳли
лілю-лілю-лі
всі вже сплят
засни, маленька, й ти

Як зароб''ю двіста злотих
то збудую тобі дім
будеш спала як царівна
на пелюстках в домі тім
добраніч, доню, спім...

А в садочку твому буде
повно яблунів і груш
будем тебе колисали
в ароматах білих руж
добраніч
очка змруж

У крамничці куп''ю меду
масло мліко яйка сіль
куликівский хліб і сало
як си збудиш жеби с мала
їсти пити повен стіл

Як зароб''ю двіста злотих
буде в нас великий баль
буде музика і танці
і забава буде...
цить...
мала царівна спить','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2176410'), datetime('now')),datetime('now'));
