INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2178550','Богородице, вiрним обороно','Виконує: Тарас Компаніченко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Богородице, вiрним обороно!
Уповающим на Тебе, Короно!
Спаси нас од бiд, Мати Преблагая, Дiво Святая!

Ти Жизнодавца на свiт породила
Адама й *Э*ву од бiд свободила
Свободи ж i нас, Мати Преблагая, Дiво Святая!

Тебе Небесних духов поють хори
Тебе Патрiарх i Пророк соборний
Всi вихваляють, Мати Преблагая, Дiво Святая!

Тебе Апостол i святитель ликий
святих женщини даже мученики
Всi вихваляють, Мати Преблагая, Дiво Святая!

Тебе пустельник й преподобних *****
Яко Царицу i всiх нас Патронку
Усердно просять, Мати Преблагая, Дiво Святая!

Та моли Сина Своэго за нами
Би не попрали враги нас ногами
Молимся Тобi,Мати Преблагая, Дiво Святая!

Предстательнице i Покрове Миру
Од эретиков храни нашу вiру
Не дай згубити,Мати Преблагая, Дiво Святая!

Абисьмо Тебе той не вихваляли
I Бога в Тройцi эдиного знали
Тому да буде од нас Честь i Хвала а навiки Слава!

Богородице, вiрним обороно!
Уповающим на Тебе, Короно!
Спаси нас од бiд, Мати Преблагая, Дiво Святая!','[''pisni.org.ua'', ''cat:do-bohorodyci'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2178550'), datetime('now')),datetime('now'));
