INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2176328','То було так давно','Музика: Віктор Морозов Слова: Андрій Панчишин. Виконує: Віктор Морозов','uk','ukraine_1991',NULL,NULL,'http://www.mo-productions.com/',NULL,'коли на Вірменскій ше жили вірмени
коли на Жидівскій ше жили жиди
коли в Стрийскім парку пасли си олені
а в крані ніколи не бракло води

То було так давно
То було так давно
То було то було
То було так давно

коли на Пекарскій пекли караваї
коли їден когут пів-Львова будив
на Замок ходили мацьопкі трамваї
то було, коли я си ше не вродив

То було так давно...

коли ше свічками світили в Опері
і били на вежах годинники всі
коли перший поверх не був на партері
і пливали в Полтві живі карасі

То було так давно...

коли на Підзамчу стояла рогатка
по цісарскім лісі блудили вовки
коли шанували і матку і батька
коли не давали до шлюбу дівки

То було так давно...

коли ше на корзо ходили батяри
на Сихови бойки пасли баранів
а люди співати могли без водяри
бракує, панове, мені давних днів

то ніколи си не верне
скорше світ си переверне
так ніколи вже не буде
не то місто
не ті люди

То було так давно
То було так давно
То було то було
То було так давно','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2176328'), datetime('now')),datetime('now'));
