INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2177614','Україна моя','(Україно, моя Україно). Музика: Вікторія Сорочик Слова: Вікторія Сорочик. Виконує: Вікторія Сорочик','uk','ukraine_1991',NULL,NULL,NULL,NULL,'У краях, що дощами омиті,
Простягнулася наша земля,
Де Карпати лісами покриті,
Де орел понад степом кружля.
Там, де батько Дніпро рукавами
Обіймає поля і сади,
Де віками живемо ми з вами,
І Господь, що нас любить завжди.

Приспів:
Україно, моя Україно,
Ти в душі і у серці живеш,
Народила і доньку, і сина,
В майбуття за собою ведеш.

І хай носить нас вітер по світу,
Хай часами суворе життя,
Я не зраджу мою Україну,
Не покину, як мати дитя!
Лине пісня дзвінка і привітна,
Де у полі дозріли хліба,
Там, де прапор наш жовто-блакитний,
Де козацькая слава жива.

Приспів. (2)','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2177614'), datetime('now')),datetime('now'));
