INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_217694','Ой у горі','Музика: Ігор Пелих Слова: Тарас Шевченко. Виконує: Нічлава Блюз','uk','ukraine_before_1917',NULL,'1859','текст [1] та акорди: аудіо: Нічлава блюз. Вставай, Сонце. 1992-1993; текст [2]: Шевченко Т. Кобзар.- Київ: Радянська школа, 1983.- 608 с.','[1]: Акорди спрощені та адаптовані до тональності Em [2]: Оригінальний текст за Т. Шевченком (Лихвин, 7 іюня 1859) Підбір акордів: bohdanko@epost.com.ua','[1]:

Ой у горі роман цвіте,
Долиною козак іде
Та й у журби   питається:      |
"З ким ж та доля   пишається?  |

Чи у шинку з багачами?
Чи у степу з чумаками?
Чи у полі на роздоллі      | (2)
З вітром віється поволі?"  |

Не там, не там, друже-брате,
У дівчини в чужій хаті,
В рушниках та й у хустині  | (2)
Захована в новій скрині.   |

[2]:

Федору Івановичу Черненку
На пам''ять 22 сентября 1859 року

Ой по горі роман цвіте,
Долиною козак іде
Та у журби питається:
"Де та доля пишається?

Чи то в шинках з багачами?
Чи то в степах з чумаками?
Чи то в полі на роздоллі
З вітром віється поволі?"

Не там, не там, друже-брате,
У дівчини в чужій хаті,
У рушничку та в хустині
Захована в новій скрині.

(Лихвин, 7 іюня 1859)','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_217694'), datetime('now')),datetime('now'));
