INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2179175','Новорічна','Слова: Zоряна. Виконує: Zоряна','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Снігом моє місто замело,
Всі ялинки куплені давно,
Друзям подарунки надсилаю,
Настрій свята в серце запускаю!
Новорічні стали магазини,
Люди розбирають апельсини,
І шампанське кожен хоче мати,
Щоб у північ келихи підняти!

Приспів:
Новий Рік іде по землі,
В інтернеті, в ефірах TV!
Новий Рік по планеті мандрує,
Бій курантів бажання дарує!

Всі мобілки у руках тримають,
Есемески друзям надсилають,
Перегруз в мережі від вітань,
Позитивних слів і побажань!

Приспів.

З Новим Роком! З Новим Роком!
З Новим Роком!

Приспів. (2)

З Новим Роком!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2179175'), datetime('now')),datetime('now'));
