INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_217869','Я поїду','(Бо я їду до моря...). Музика: Олександр Шевченко Слова: Олександр Шевченко. Виконує: Піккардійська Терція, Олександр Шевченко','uk','ukraine_1991',NULL,NULL,'http://tercia.alfaspace.net/album1.html (Аудіо-альбом "Піккардійська Терція", 1994)',NULL,'Дорога манить, вітер за спиною,
І асфальт, як масло, м''який.
Музика грає, і ніхто не знає,
Чом я веселий такий.

Бо я їду до моря, де зустрінусь з тобою,
Поки ще незнайомою, о-о-о-о.
Бо я їду до моря, море вже за горою,
І якою ти будеш, мені все одно.
І якою ти будеш, мені все одно.

Море зустріне і приголубить,
Хай буде повний штиль.
Чайки співають, і вони не знають,
Чом я веселий такий.

Бо я їду до моря, де зустрінусь з тобою,
