INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2182495','Заповіт вчителя','Музика: Володимир Шинкарук Слова: Володимир Шинкарук. Виконує: Володимир Шинкарук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Як умру то поховайте
Подалі від школи,
На педраді не згадуйте
Більше вже ніколи.
На вінок мені не тратьте
Ні грошей, ні часу,
Бо я маю, що вчительство
Не має запасу.
На могилі покладіте
Які-небудь квіти,
А в головах заховайте
План самоосвіти.
Зошит, ручку і щоденник
Дайте мені в руки,
І згадайте, друзі милі,
Муки мої, муки.

Прощавайте назавжди,         |
Двійки й одиниці,            |
Й ви, колеги-вчителі,        |
Й вчителиці.                 | (2)

Не прожив я так, як люди,
Не досипав ночі,
Над тими зошитами
Вилазили очі.
З''їла школа моє серце
І ще пів печінки,
Бо за нею я не бачив
Ні діток, ні жінки.
Місцевкому передайте
Моє шанування,
Так путівки не діждався
Я на лікування.
Ну а заучу скажіте,
Хай розклад міняє,
Бо мене вже на цім світі
Живого немає.

Прощавайте назавжди,
Педради й уроки,
Й ви, колеги-вчителі,
І вчительохи.

Директору передайте
Мою шану й дяку,
Нехай тепер поцілує
Мене в саму руку.
Треба вам запам''ятати
Вчителі майбутні:
В школі добре працювати,
Як не мав ні учнів.
Може станеться колись,
Що буде зарплата,
То випийте ви за мене
По сто грам на брата.
Ось і все, тепер прощайте,
Бо я точно знаю,
Хто учитель на цім на світі, |
Той іде до раю!              | (3)','[''pisni.org.ua'', ''cat:bardivski'', ''cat:philosophic'', ''cat:shkilni'', ''Бардівські пісні'', ''Філософські пісні'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2182495'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2182495','Заповіт вчителя','Як умру то поховайте
Подалі від школи,
