INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2179457','Верба','Виконує: Спека Така','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гей, на Івана, гей, на Купала,
В темному лісі папороть цвіте,
Ой, у полі верба, стоїть верба,
Ой, да,
Покохала дівчина козака,
Ой, да.
Тая любов, наче пташка летить
І перешкод немає,
Моя любов як струмочок біжить,
Серце моє палає.

Приспів:
Думати не думала,
Знати не знала я,
Що раптово покохаю я тебе,
Як у лісі самотньо блукала я
І квітки збирала я!
Як у коси вінки заплітала я
З квітів, трав та співала пісні.
На Івана Купала гадала я,
Папороть шукала я,
цілу ніч не спала я!

Ясне сонечко в ланах зішло,
Ой, да...
Як кохання моє, моє прийшло,
Ой, да, ой, да!
Тая любов, наче небе блакить,
Без перешкод, без краю.
Моя любов, не кидай ні на мить,
Серце моє палає!

Приспів.

Гей, на Івана, гей, на Купала,
В темному лісі папороть цвіте,
Ой, у полі верба, стоїть верба,
Ой, да!
Гей, на Івана, гей, на Купала,
Гей, на Івана, гей, на Купала!
Покохала дівчина козака,
Ой, да.

Приспів.

Ой, у полі верба...','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2179457'), datetime('now')),datetime('now'));
