INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2183990','Ой, веснонько, весно',NULL,'uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно-літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.',NULL,'Ой, веснонько, весно,
Що ти нам принесла?
Гей!

Принесла вам літо,
Зеленее жито.
Гей!

Гей, гей!
Принесла вам квіточок
У вишневий садочок,
Гей, щоб красні дівочки,
Гей, та й плели віночки.
Гей!

Гей, гей!
А хлопцям по дудочці,
Та ще й по сопілочці,
Гей, щоб весело грали,
Гей, землю звеселяли!
Гей!','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2183990'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2183990','Ой, веснонько, весно','Ой, веснонько, весно,
