INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2184420','Жучок','(Ходить жучок по драбині). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.','Опис гри: Доросла молодь стає парами, узявшись за руки "в замок" — себто, кожен правою рукою тримає власну ліву вище зап''ястя, а лівою береться так само за праву руку своєї пари. Таким чином кожна пара утворює своїми руками немов би "сходинку". По цих сходинках і йде Жучок — маленька дівчинка або хлопчик, якого підтримують за руки двоє високих і міцних учасників гри. Кожна пара, яку Жучок перейшов, перебігає наперед, знов утворює сходинку, і Жучкові забезпечена дорога по "драбині".','Ходить жучок по драбині,
А жучиха по ряднині.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

А ми того рік чекали,
Щоби нині жучка грали.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

А наш жучок невеличкий,
На жучкові черевички.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

На жучкові опанчина,
А сам жучок як дитина.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

На жучкові жупан драний,
А сам жучок п''яний, п''яний.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

На жучкові жупан куций,
А сам жучок чорновусий.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

Дівки жучка підпоїли,
На нім жупан підкроїли.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

Дайте, дівки, околота,
Повезем жучка до болота.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

Жучок плаче у болоті,
Дівки скачуть у золоті.

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)

А в нас верби-груші родять,
А в нас дівки в злоті ходять!

Грай, жучку, грай, небоже, |
Най ти пан Біг допоможе!   | (2)','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2184420'), datetime('now')),datetime('now'));
