INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2184512','Ой, сходіться, дівчаточка','(Гей, ставаймо). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.','Опис гри: Під мелодію "Гей, ставаймо, дівки, в коло" можна й потанцювати. Дівчата беруться за руки і йдуть по колу характерним кроком: Гей, - крок правою ногою вбік праворуч ста- - ліва нога стає поруч із правою вай- - крок правою ногою вбік праворуч мо, - рух лівою ногою вперед-праворуч дів- - ліва нога стає поруч із правою ки, - рух правою ногою вперед-ліворуч в ко- - крок правою ногою вбік праворуч ло... - ліва нога стає поруч із правою. Далі ці рухи повторюються. Потім на повільну мелодію дівчата розходяться з кола, а на швидку знову збираються і танцюють.','Ой, сходіться, дівчаточка,
Усі докупочки!           | (2)
Та ми собі заспіваєм
Файні співаночки.        | (2)

Та ми цього, дівчаточка,
Цілий рочок ждали,       | (2)
Щоби-м cecі співаночки
Нині заспівали.          | (2)

Гей, ставаймо, дівки, в коло,
Заспіваймо си весело!
Гей, гей, го-я, го-я,
Голівонько бідна моя!

Ой, ти веснонько, веснися,
А ти, парубче, женися!
Гей, гей, го-я, го-я,
Голівонько бідна моя!

Вибирай си з рожі квітку,
Молоду Ганнусю-дівку.
Гей, гей, го-я, го-я,
Голівонько бідна моя!

Вітер віє, вітер віє,
Ще й сонечко гріє.       | (2)
Яка весна веселенька -
Всюди зеленіє!           | (2)

Яка весна веселенька -
Пташечка співає,         | (2)
Яка така галузочка,
Вна ся розвиває.         | (2)

Яка така галузочка -
Червона калина.          | (2)
Як зозулька закувала -
Світ розвеселила!        | (2)

Гей, ставаймо, дівки, в коло,
Заспіваймо си весело!

Ой, на горі жито, жито,
А в долині овес.         | (2)
Усі дзвони задзвонили,
Кажуть: Христос воскрес! | (2)

Як задзвонять усі дзвони,
Чути аж на гору.         | (2)
Збирайтеся, добрі люди,
До Божого дому!          | (2)

Збирайтеся, добрі люди,
Слухайте науки,          | (2)
Як Сус Христос та й на хресті
Терпів за нас муки.      | (2)

Як Сус Христос та й на хресті
Мученьки приймає,        | (2)
Ми не годні відмолити,
Що Господь нам дає.      | (2)','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2184512'), datetime('now')),datetime('now'));
