INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185267','Ой, чиє то поле заспівало стоя?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой, чиє то поле
Заспівало стоя?
Заспівало нам,
Хорошим женцям. Гу!

Іванове поле
Заспівало стоя.
Ми його дожнем,
У копи складем. Гу!

А чужії женці
Та все шолудивці -
Жита не пожали,
Серпи поламали. Гу!

А нашії женці
Та все чорнобривці -
Житечко дожали,
В снопи пов''язали. Гу!','[''pisni.org.ua'', ''cat:obzhynkovi'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185267'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185267','Ой, чиє то поле заспівало стоя?','Ой, чиє то поле
Заспівало стоя?
Заспівало нам,
Хорошим женцям. Гу!

Іванове поле
Заспівало стоя.
Ми його дожнем,
У копи складем. Гу!

А чужії женці
Та все шолудивці -
Жита не пожали,
Серпи поламали. Гу!

А нашії женці
Та все чорнобривці -
Житечко дожали,
В снопи пов''язали. Гу!');
