INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2185495','Колискова','(Спи, засни, моя дитино, спи, моє маля...). Музика: Роман Свистун Слова: Андрій Малишко','uk','ukraine_before_1917',NULL,NULL,'Збірка пісень "Край ромашковий"',NULL,'Спи, засни, моя дитино, спи, моє маля,
Ніч іде в гаї, долини, трави нахиля.
Хай тобі ця ні насниться, що в огнях сія.
Будеш завтра в світ дивитися, зіронько моя!

Перша ніч твоя почата
В співах солов''я,
Дай же мамі рученята,
Зіронько моя.

Посміхнись до мене, синку,
І зрадію я,
Не хвилину і не днину -
Я навік твоя.

Сплять ліси, поля, криниці,
Шепіт ручая.
Ти відкрий, відкрий очиці,
Юносте моя.

Підеш ти по Україні,
Де життя буя.
Виростай, моя дитино,
Зіронько моя!','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2185495'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2185495','Колискова','Спи, засни, моя дитино, спи, моє маля,
Ніч іде в гаї, долини, трави нахиля.
Хай тобі ця ні насниться, що в огнях сія.
Будеш завтра в світ дивитися, зіронько моя!

Перша ніч твоя почата
В співах солов''я,
Дай же мамі рученята,
Зіронько моя.

Посміхнись до мене, синку,
І зрадію я,
Не хвилину і не днину -
Я навік твоя.

Сплять ліси, поля, криниці,
Шепіт ручая.
Ти відкрий, відкрий очиці,
Юносте моя.

Підеш ти по Україні,
Де життя буя.
Виростай, моя дитино,
Зіронько моя!');
