INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_21879','Батько і мати','Музика: Олександр Злотник Слова: Вадим Крищенко. Виконує: Назарій Яремчук, Іво Бобул, Василь Білоцерківський, Дмитро Хома','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Знайдеться на усе причина,
Для тишини і для грози.
Та дивиться синок очима,
А в них дві крапельки сльози

І крізь образи і розлуки
Печаль дітей знов нас пече.
Їм треба материнські руки,   |
Їм треба батьківське плече.  | (2)

Приспів:
Батько і мати, два сонця гарячих,
Що нам дарують надію й тепло.
Батько і мати, у долі дитячій
Треба щоб кривди між них не було.

В душі то пісня солов''їна,
То злякано сичі кричать.
Щоб не кришилася родина,
Нам треба вміти і прощать

Нехай людські любов і шана
Осилять всі шляхи круті.
Бо в дітях ми себе лишаєм,  |
Себе продовжуєм в житті.    | (2)

Приспів. (2)','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_21879'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_21879','Батько і мати','Знайдеться на усе причина,
