INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2188716','Не дощ','Музика: Андрій Підлужний Слова: Андрій Підлужний. Виконує: Тіна Кароль','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Давай без сліз завершимо любов,
Без зайвих слів,
Образ і звинувачень,
І в той момент,
Коли пульсує ненависть і кров,
Протягнемо назустріч руки.

Приспів:
Не дощ і не сніг
Стримати мене не зміг...
Не дощ і не сніг...
Не дощ і не сніг,
Ніколи я б піти не зміг,
Не дощ і не сніг...

Давай від всіх збудуємо стіну,
Від злих очей,
Проклять і наговорів,
І в той момент,
Коли сім''я порветься, як струна,
Відкрий мені назустріч двері.

Приспів. (2)','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2188716'), datetime('now')),datetime('now'));
