INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218653','Ой підемо пане-брате...','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1991','В дитинстві навчила баба','Цю колядку чув надзвичайно рідко лише від людей, що походять з Яворівщини, Перемишльчини, Любачівщини, Ярославщини (Польща). Також трапився мені текст (частина) цієї колядки, надрукований у районній багатотиражці Дрогобиччини "Галицька зоря" 5 січня 1991 року. Доповнення від "bohdanko" (модератор): Ноти з акордами та міді зроблено на слух; потребують уточнення.','Ой підемо, пане-брате,
Від хати до хати
Нашим панам-господарям
Заколядувати.

Ой колядо-колядочко
Ти нам дуже мила
Де пречиста діва-мати
Сина породила.

Породила єго в яслах
В селі Вифлеємі
Зажурився можний Ірод
Во Єрусалимі.

А пастирі посходились
Поклін єму дати
І пречисте боже світло
На землі витати.

Ой підемо пане-брате
Від хати до хати
З Колядою щастя й долі
Людям побажати.    Мелодія для 1 голосу','[''pisni.org.ua'', ''cat:halycki'', ''cat:kolyadky'', ''Пісні з Галичини'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_218653'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_218653','Ой підемо пане-брате...','Ой підемо, пане-брате,
