INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218890','Ой, я мала чоловіка','(Ворона). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Фонотека етнолабораторії',NULL,'Ой, я мала чоловіка, чоловіка мала,
Посадила на пеньочку, та й ворона вкрала.
Ой, не чула я такого, та й не виділа,
Щоб ворона чоловіками обідала.
Ой, вороно, ти, вороно, сіла на пеньочку,
Коли з"їла чоловіка - віддай хоч сорочку.
Ой, вороно, ти, вороно, ти, вороно кара,
Віддай мені чоловіка, бо то ж моя кара.
...Хоч яка ворона, а в дворі оборона...','[''pisni.org.ua'', ''cat:volynski'', ''Пісні з Волині'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_218890'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_218890','Ой, я мала чоловіка','Ой, я мала чоловіка, чоловіка мала,
