INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2188158','Моліться люди всі до Бога','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Пісню виконує Іван Бабій.','Моліться люди всі до Бога
Моліться за своїх дітей
За церкву, волю, Україну
За твердість віри всіх людей.

Приспів:
Моліться діти всі до Бога
Моліться за своїх батьків
За те,щоб голуб миру й волі
Над нами все життя летів.

Чому ми в світі так живемо
В гріхах без Бога і в брехні
Чому сини не люблять батька
Повчання матері марні.

Приспів.

В нас перша мати є Марія.
Другая - Церковця свята
А третя - мати Україна
Четрерта - Ненька дорога.

Приспів.

О, Пресвятая, Божа Мати,
Додай у вірі нам снаги
Щоб ми в любові, в мирі жили
Не знали гордості й нужди.

Приспів.

Давайте за руки візьмемось
Дорослі, юні, молоді
І всі разом прославимо Бога
На рідній матінці землі.

Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christian'', ''Церковні пісні'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2188158'), datetime('now')),datetime('now'));
