INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2189394','Шануйте батьків','Виконує: Берники','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Не завжди буде шумно у нашій хаті,
Не завжди буде в дворі дітвора,
Не вічно з нами будуть батько й мати, |
З дитинства в юність перейде життя.   | (2)

Не завжди будуть нам допомагати,
Тим діткам, що були колись разом,
Роки не ті - крізь сльози скаже мати,
Тремтячим голосом і зморщеним чолом.
Не ті роки - крізь сльози скаже мати,
Тремтячим голосом і зморщеним чолом.

Роки міняють молодість на старість
І прийде час, прийде така пора:
Нас спогади повернуть у дитинство,     |
Як стануть дійсністю проспівані слова. | (2)

Не забувайте батьків шанувати,
Не забувайте їхнього тепла,
Не вічно з нами будуть батько й мати,
З дитинства в старість перейде життя.
Бо не вічно з нами будуть батько й мати,
З дитинства в старість перейде життя.

Не завжди буде шумно у нашій хаті,
