INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218990','Вже Весна воскресла (3)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Вже Весна воскресла. Принесла Вам Росу Панєньскую Красу. Панєньская Краса в Меду ся Купала. Івана купала тай в Воду упала. Можливий РОЗСПІВ, Вже Весна воскресла (2): Вже Вес-на вос-кре-е-ес-ла Що жіс на-ам при-нес-ла |(2) Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа. Вербний Тиждень і Шутка. Про Українські назви місяців Марець і Май.','Вже Весна воскресла
