INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_218952','Весно Наша Весно що Ти нам принесла (3)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Пара — любощі: Роса-Краса. Плуг-Батіг-Барвінок-Вінок. Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Вже Весна воскресла. Принесла Вам Літо щоб родило Жито. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Про Українські назви місяців Марець і Май. Стежки до листків про Українські традиції. Висловлювання: Відчути і зрозуміти. Відчути і зрозуміти все те багатство почуття і гадки, краси й сили, яке вложено й заховано в нашій словесній спадщині. Бо ми володіємо в сій спадщині засобами далеко більшими, ніж хто-небудь думає — і ніж думаємо ми самі. Світ не оцінив їх досі відповідно — і се не диво, коли ми самі не свідомі їх властивої ціни й міри. Так, не знаємо їх і не цінимо їх, — тому між іншим, що шкільна практика, яка й досі панує в виучуванні нашої красної словесности, особливо старшої, своїми схоластичними методами відстрашує навіки від безпосередньої знайомости з її пам''ятками своїх виучеників. — М. Грушевський.','Весно Наша Весно
Що Ти нам принесла     | (2)
Принесла Вам Літо
Щоб родило Жито !      | (2)

Приспів:
Старим Бабам по Лопаточці
Молодицям по Дитяточці
Чоловікам по Плужку
Xлопчикам по Батіжку
А Дівчатам по Віночку
з Xрещатого Барвіночку!

Весно Наша Весно
Що Ти нам принесла     | (2)
Принесла Вам Росу
Парубоцьку Красу!      | (2)','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_218952'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_218952','Весно Наша Весно що Ти нам принесла (3)','Весно Наша Весно
