INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2192091','Стяги в''ються малинові','Музика: Геннадій Татарченко Слова: Раїса Кириченко. Виконує: Раїса Кириченко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гей, широке поле
Пшеницями грає,
А в тім полі пан полковник
З хлопцями гуляє!
Ой, полковник синьоокий
На коні буланнім,
Їдуть за ним козаченьки  |
В битвах нездоланні!     | (2)

Приспів:
Стяги в''ються,
Стяги в''ються малинові,
Їдуть хлопці,
Їдуть хлопці чорноброві.
Попереду пан полковник,  |
Попереду пан полковник,  |
Мій полковник синьоокий! | (2)

Зупинились козаченьки
Спочить біля ставу
Та й пустили коней пастись
В шовкову отаву.
А там дівки-чарівниці
Полотно білили,
А коники копитами        |
Всі рушники збили.       | (2)

Ой, дівчата на коників
Серцем не сварились,
Біля ставу з козаками
До ранку мирились.
Рано-вранці козаченьки
В похід вирушали,
А дівчата рушниками      |
Дорогу встеляли.         | (2)

Приспів.

Попереду пан полковник,
Попереду мій полковник,
Мій полковник синьоокий!
Попереду пан полковник,
Попереду пан полковник,
Мій полковник синьоокий!','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2192091'), datetime('now')),datetime('now'));
