INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2190251','Ведмедик і лісові звірята','Музика: Василь Верховинець (Костів) Слова: Василь Верховинець (Костів)','uk','ukraine_1991',NULL,NULL,'В. Верховинець. Весняночка. Ігри з піснями для дітей дошкільного віку та молодших школярів. Видання четверте, перероблене і доповнене. - Київ: Музична Україна, 1979. - 339 с.','Опис гри: Діти — Лісові звірята утворюють замкнене коло і умовно поділяють його на два півкола: перше та друге. Посередині на стільчику (під дубком) спить Ведмедик. Починається пісня. У першому куплеті Лісові звірята обережно ходять у колі зальотним рухом, ніби підкрадаються до того, хто заснув там під "дубком", а на "Цс-с-с!" присідають до землі. У другому куплеті Лісові звірята першого півкола обережно наближаються до центру і на "Цс-с-с!" присідають біля стільчика. У третьому куплеті до першого півкола приєднується й друге, адже Лісовим звірятам дуже цікаво знати, хто ж то все-таки заснув. Хоч Звірята добре стереглись, проте розбудили Ведмедика, впізнали його та й кричать. Лісові звірята кидаються врозтіч, Ведмедик за ними. Кого він спіймає, той сідає замість нього на стільчику (під дубком), і гра починається спочатку. Мета: розвивати у дітей спритність.','Хто то спить під дубком,
Ще й накрився кожухом?
Цс-с-с!

Тихо, тихо, не будіть,
То, напевно, спить ведмідь.
Цс-с-с!

Стережіться, бо той гість,
Як устане, всіх поїсть.
Цс-с-с!

Ой, рятуйтесь від біди,
Утікайте, хто куди!','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2190251'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2190251','Ведмедик і лісові звірята','Хто то спить під дубком,
