INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2191993','Моя подруго мила','Українська народна пісня. Виконує: Раїса Кириченко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Пам''ятаю, в засіяні розпачем дні,
В найскрутнішу, найтяжчу життєву хвилину
Посміхнулася доля правдиво мені
І послала, як подругу, щиру людину.
Коли пада надія жжЖовтневим листом,
І роз''ятрене серце пече,
Ти, мов птах милосердя, прикриєш крилом,
Безкорисно підставиш плече.

Приспів:
Моя подруго мила, нас життя поріднило,
Я для тебе у серці гніздечко зів''ю,
Білосніжною вишнею звірини навколишньої |
Ти приходиш до хати і в душу мою!       | (2)

Прошуміли веснянками наші роки,
Та незмінно, як матері погляд ласкавий,
Я тепло відчуваю твоєї руки
І нестримні очей твоїх добрих заграви.
Будуть свідками нашої дружби завжди
Світлі зорі в нічній тишині.
Ти потрібна в годину лихої біди,
Ти потрібна і в щастю мені!

Приспів. (2)

Ти приходиш до хати і в душу мою...','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2191993'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2191993','Моя подруго мила','Пам''ятаю, в засіяні розпачем дні,
В найскрутнішу, найтяжчу життєву хвилину
Посміхнулася доля правдиво мені
