INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219063','Українська душа','Музика: Олександр Пляченко Слова: Вадим Крищенко. Виконує: Микола Гнатюк','uk','ukraine_1991',NULL,NULL,NULL,'Я маю цю пісню у аранжуванні Володимира Ядчишина, а співаю, звісно, сам.','У добру годину, у світлу хвилину
Хорошої пісні звучить передзвін.
Господарю-батьку і ви, господине,
Приміте низький та сердешний уклін.

Приспів:
Хай пісня привітна до вас доліта
На щастя, на долю, на довгі літа.
Хай стіл не загубить гостинця-коржа
І сонечком світить українська душа.

Всміхнулася хата запрошенням щирим,
Мов соняхи, вікна її розцвіли.
Хай пахне у хаті любов''ю і миром,
І щастя рушник застеляє столи.

Приспів.

Господарю-батьку і ви, господине,
Хай доленька ваша рясніє щодня
Привітом родини і цвітом калини,
І всі ми - велика, єдина сім''я.

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_219063'), datetime('now')),datetime('now'));
