INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219420','Засумуй трембіто','Музика: Роман Купчинський Слова: Роман Купчинський. Виконує: Богдан Косопуд, Євгенія Зарицька','uk','ukrainian_peoples_republic_1917_1921',NULL,'1920','1. Цей текст записав у 80-х роках від побратима родом з Коломиї. 2. Пісні українських січових стрільців, - 1990. 32 с. (Самвидав). 3. Сурма. Збірник воєнних пісень.- Львів-Київ: Червона Калина, 1922.','Наприкінці 80-х років чув у виконанні "Черемоша" 1, 2, 4 і 7 в''язки цього тексту, траплялися й інші виконавці неповного варіанту пісні. Вказані в''язки є первісним варіантом Романа Купчинського цієї пісні. У джерелі 2 є помилка у третьому такті нот, відсутній восьмий такт. Ймовірно, що джерело 2 є переписом із джерела 3, у якому також є помилка у третьому такті: остання нота повинна бути восьмою або дві передостанні - шістнадцятими. Один з варіантів виправлення поданий у доданих файлах. Із джерела 3: "Пісня про лихоліття, яке навістило УГА на Україні. Зродилася в Київі під большевиками 1920 р." Підбір акордів: bohdanko (pisni.org.ua)','Засумуй, трембіто,
Та (й) по всему світу,
Що зів''яло галичанам       |
Сорок тисяч цвіту.         |(2)
Засумуй, трембіто,
Та (й) на всі Карпати,
Щоб не ждали сина з войни  |
Ні отець, ні мати.         |(2)
Засумуй, трембіто,
На всю полонину,
Де покинув кожен стрілець  |
Молоду дівчину.            |(2)
Засумуй, трембіто,
Та (й) на все Поділля,
Щоб не ждала дівчинонька   |
Хлопця на весілля.         |(2)
Засумуй, трембіто,
Та (й) на всі долини,
Не побачить козаченько     |
Любої дівчини.             |(2)
Засумуй, трембіто,
На всю Україну,
