Сорок тисяч цвіту.    |(2)','[''pisni.org.ua'', ''cat:halycki'', ''cat:istorychni'', ''cat:strilecki'', ''Пісні з Галичини'', ''Історичні пісні'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_219420'), datetime('now')),datetime('now'));
