INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219277','Колисонька кленовая','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Чув у родині.',NULL,'Ой співаю колисанку
Тихеньку, тихеньку
Про кленову колисоньку,
Дитину маленьку.

Колисонька кленовая
Рипуча, рипуча,
Дитинонька малесенька
Плакуча, плакуча.

А я буду колисоньку
Гойдати, гойдати,
А я свою дитиноньку
Буду колисати.

Бережи нам, дитинонько,
Нашу рідну мову,
Нашу чисту солов''їну
Пісню колискову.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_219277'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_219277','Колисонька кленовая','Ой співаю колисанку
Тихеньку, тихеньку
Про кленову колисоньку,
Дитину маленьку.

Колисонька кленовая
Рипуча, рипуча,
