INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2191920','Чураївна','Музика: Микола Збарацький Слова: Станіслав Реп''ях. Виконує: Раїса Кириченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Там, де Ворскла пливе поміж берегами,
Чарівниця живе з чорними бровами.
Знають зілля її в нашім ріднім краї
І мовчать солов''ї, як вона співає.

Приспів:
Лунає мелодія дивна,
Мов ніжна і чиста любов,
Царівна пісень - Чураївна
До нас повернуся знов!
Лунає мелодія дивна,
Мов ніжна і чиста любов,
Царівна пісень - Чураївна
До нас повернуся знов!

Чи радіє вона, чи вона сумує -
Милий голос луна, і усіх чарує.
Спалахнули гаї полум''ям калини,
То співає вона - донька України!

Приспів. (3)','[''pisni.org.ua'', ''cat:devoted'', ''Пісні присвячені окремим особам'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2191920'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2191920','Чураївна','Там, де Ворскла пливе поміж берегами,
Чарівниця живе з чорними бровами.
Знають зілля її в нашім ріднім краї
І мовчать солов''ї, як вона співає.

Приспів:
Лунає мелодія дивна,
Мов ніжна і чиста любов,
Царівна пісень - Чураївна
До нас повернуся знов!
Лунає мелодія дивна,
Мов ніжна і чиста любов,
Царівна пісень - Чураївна
До нас повернуся знов!

Чи радіє вона, чи вона сумує -
Милий голос луна, і усіх чарує.
Спалахнули гаї полум''ям калини,
То співає вона - донька України!

Приспів. (3)');
