INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219369','Львів','Виконує: Монте-Крісто','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Новий день,він у темних окулярах,
Тихо вийшов на двір,
Іде по вулицях старих.
Всі люди зайняті,є справи, розмови.
Знову дощ, на вулицях Львова.
Під парасолями ховають свої гриви,
Сильні камінні леви,
Такі сумні і ліниві.
Їх теплий погляд не скаже ні слова.
Знову дощ на вулицях Львова.

По двох паралелях летить мій трамвай,
Мій трамвай везе мене знову.
Вертаюсь до тебе, мене зустрічай,
Зустрічай на вулицях Львова.

