INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2193726','З Новим Роком!','Музика: Зірка Колос Слова: Зірка Колос. Виконує: Зірка Колос','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На щоках твоїх сніжинки,
Сяйвом світяться ялинки
І біжать кудись хвилинки
Ненароком, ненароком...
Морозець малює шибку,
Наближається так швидко
Час, коли ми заспіваєм:
"З Новим Роком!"

Приспів:
Новий Рік крокує по землі,
Новий Рік співає,
Щастя принесе він тобі і мені,
Хай кожне бажання твоє
Він здійсняє!

Несміливо поцілуєш,
Своє серце подаруєш,
Світ кохання ти відкриєш
Крок за кроком, крок за кроком...
І з ялинкою красиво
Наше новорічне диво
Нам щасливо прошепоче:
"З Новим Роком! З Новим Роком!"

Приспів. (2)

Хай кожне бажання здійсниться
