INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2194328','Свіча','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ніч і тільки зорі за вікном,
Ніч, усе поснуло тихим сном...
Тільки сон мій так далеко
Відлетів, немов лелека,
Я встаю й запалюю свічу...
Тільки сон мій так далеко
Відлетів, немов лелека,
Я молитву тихо шепочу...

Приспів:
Гори, гори, моя свіча,
За тих, хто ще живий,
За тих усіх, хто по землі
І досі топче ряст.
Гори, гори, моя свіча,
За рідних, дорогих,
За тих, хто вже пішов від нас...

Ніч, я знову Господа молю,
Ніч, за тих усіх кого люблю.
Знаю, сон мій так далеко
Відлетів, немов лелека,
Та горить у темряві свіча.
Знаю, сон мій так далеко
Відлетів, немов лелека,
І сльоза зрадлива на очах...

Приспів.

Тільки сон мій так далеко
Відлетів, немов лелека,
Я встаю й запалюю свічу...
Тільки сон мій так далеко
Відлетів, немов лелека,
Я молитву тихо шепочу...

Приспів. (2)','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2194328'), datetime('now')),datetime('now'));
