INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2194616','Лісапед','Музика: Наталія Фаліон Слова: Наталія Фаліон','uk','ukraine_1991',NULL,'2008',NULL,'пісня сучасна, виконувалась на "Сорочинському ярмарку" у 2008 році','Продавала самогон, продавала
Трохи грошей я собі назбирала
На базарі лісапед я придбала
Найкрутіша на селі баба стала

Приспів
Лісапед мій, лісапед
Двохколісний "Гранд Черокі"
І дзвінок великий є
Шкіряне сідло широке
На багажник покладу
Два мішки із буряками
Я лечу через село
Лісапедом, наче танком

Я ганяю по селі і балдію
Зупинити лісапед ще не вмію
А на рамі кум сидить і регоче
Я кажу йому: "Гад, злізай", - а він не хоче

Приспів.

Газували по селі аж до ночі
Обнімає мене кум і лоскоче
Ну кому яке є діло до того
Що катаю по селі кума свого

Приспів.

