INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2194410','Дорога додому','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На світі є багато непройдених доріг,
Та лиш одна додому повертає,
Там у садочку хата, неначе оберіг,
Вона усе життя мене чекає.

Приспів:
Там яблунька цвіте, мене у сад веде
Мого дитинства стежечка знайома,
І завмирає світ, бо не бува ніде
Мені так гарно, як у себе вдома!

Життя моє складають дороги і пісні,
Та не боюся я лихої втоми,
Бо серце зігріває усе життя мені
Моя дорога, що веде додому.

Приспів.

Я знову від''їжджаю в далекії краї
Та серце на Вкраїні залишаю,
Бо там моя калина і клекіт журавлів
І хата, що завжди мене чекає.

Приспів.

І завмирає світ, бо не бува ніде
Мені так гарно, як у себе вдома!
Мені так гарно, як у себе вдома,
Мені так гарно, як у себе вдома...','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2194410'), datetime('now')),datetime('now'));
