INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2194471','Шкільна пісня','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я прийду до школи, двері відчиню,
Радісно зустріну вчительку свою.
В добрі її очі щиро подивлюсь
І нічого в світі не боюсь.

Приспів:
Будем разом рахувати
І читати, і писати,
У веселі ігри грати цілий день!
Будем разом рахувати
І читати, і писати,
І співати радісних пісень!

Весело у школі вчитись дітворі,
Вчителька стрічає діток на зорі,
Хоч давно на скронях в неї сивини,
Наче рідна мама нам вона.

