INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_219573','Чорнобильська зона','Музика: Тарас Петриненко Слова: Тарас Петриненко. Виконує: Тарас Петриненко, Гроно','uk','ukr_ssr_1919_1991',NULL,'1986','Гуру','Пісня про Чорнобильську катастрофу, яка сталася 26 квітня 1986 року на Чорнобильській АЕС. Це пісня з аудіо-альбому "Я професійний раб" Тараса Петриненка. Підбір акордів: Гуру','Em
Все зійшло нанівець,
C
Ось і казці кінець,
Що народу нема переводу.
Em
Хто в своєму дворі
C
Позасіював смерть,
Дочекався таки врешті-решт
Відповідного сходу
H
І плоду.
G
Білокровий наш страх,
Чорнокровий наш сміх
Ані спасу нема, ні заслону
G
За який же такий
Незамолений гріх
Am
Увійшла в нашу плоть
Чорнобильська Зоно?
Чорнобильська Зоно...

Ми народу сліпці,
Ще й сліпий поводир
Сплюндрували і землі, і ріки
Вірним курсом завжди.
Та весь час не туди,
Ми слухняно крокуєм,
Мов Богом забуті навіки
Каліки.
Рукотворна біда
Чернівецьких дітей
І лахміття земного озону.
Чи скінчиться потік
Смертоносних вістей,
Що співзвучні тобі
Чорнобильська зона?

Той пропив отчий дім,
Продає отчий край,
Той прокляв материнськеє слово.
Цей на горі людськім
Вимуровує рай,
Свій неправедний рай,
У якому словесна полова -
Основа.
А душа дотліва
У горнилі буття
Мов святезна дідівська ікона.
Чи знайдемо в собі
Щирих сліз каяття
Чи майбутнє у нас -
Чорнобильська зона?','[''pisni.org.ua'', ''cat:chornobyl'', ''cat:suspilno-politychni'', ''Чорнобильська катастрофа: пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_219573'), datetime('now')),datetime('now'));
