INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2194919','Диво-дівчинка','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'А у нашому у класі
Диво-дивина -
Вранці дівчинку новеньку
Мама привела
І замовкли всі одразу
В класі хлопчики,
Дивувались на полицях
Стомлені книжки.

Приспів:
А у неї очі сині
І кирпатий ніс,
Підійду і запитаю -
Як вас звати, міс?
Я віддам їй ляльку Барбі,
Нового слона -
Все для того, щоб сміялась |
Весело вона.               | (2)

А вона сміється,
Наче промінець ясний,
І від посмішки тієї
Радісно мені.
Мов метелики злітають
Голубі стрічки,
Завмирають на полицях
Радісні книжки.

Приспів. (3)','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2194919'), datetime('now')),datetime('now'));
